package main

import (
    "errors"
    "sync"
)

type Bank struct {
    mu       sync.RWMutex
    accounts map[string]int64
}

func NewBank() *Bank {
    return &Bank{
        accounts: make(map[string]int64),
    }
}

func (b *Bank) CreateAccount(accountID string, initialBalance int64) error {
    b.mu.Lock()
    defer b.mu.Unlock()

    if _, exists := b.accounts[accountID]; exists {
        return errors.New("account already exists")
    }

    if initialBalance < 0 {
        return errors.New("initial balance cannot be negative")
    }

    b.accounts[accountID] = initialBalance
    return nil
}

func (b *Bank) GetBalance(accountID string) (int64, error) {
    b.mu.RLock()
    defer b.mu.RUnlock()

    balance, exists := b.accounts[accountID]
    if !exists {
        return 0, errors.New("account not found")
    }

    return balance, nil
}

func (b *Bank) Deposit(accountID string, amount int64) error {
    if amount <= 0 {
        return errors.New("deposit amount must be positive")
    }

    b.mu.Lock()
    defer b.mu.Unlock()

    balance, exists := b.accounts[accountID]
    if !exists {
        return errors.New("account not found")
    }

    if balance > 0 && amount > (1<<63-1)-balance {
        return errors.New("deposit would cause overflow")
    }

    b.accounts[accountID] = balance + amount
    return nil
}

func (b *Bank) Withdraw(accountID string, amount int64) error {
    if amount <= 0 {
        return errors.New("withdrawal amount must be positive")
    }

    b.mu.Lock()
    defer b.mu.Unlock()

    balance, exists := b.accounts[accountID]
    if !exists {
        return errors.New("account not found")
    }

    if balance < amount {
        return errors.New("insufficient funds")
    }

    b.accounts[accountID] = balance - amount
    return nil
}

func (b *Bank) Transfer(fromAccountID, toAccountID string, amount int64) error {
    if amount <= 0 {
        return errors.New("transfer amount must be positive")
    }

    if fromAccountID == toAccountID {
        return errors.New("cannot transfer to the same account")
    }

    b.mu.Lock()
    defer b.mu.Unlock()

    fromBalance, fromExists := b.accounts[fromAccountID]
    if !fromExists {
        return errors.New("source account not found")
    }

    toBalance, toExists := b.accounts[toAccountID]
    if !toExists {
        return errors.New("destination account not found")
    }

    if fromBalance < amount {
        return errors.New("insufficient funds")
    }

    if toBalance > 0 && amount > (1<<63-1)-toBalance {
        return errors.New("transfer would cause overflow in destination account")
    }

    b.accounts[fromAccountID] = fromBalance - amount
    b.accounts[toAccountID] = toBalance + amount
    return nil
}

func (b *Bank) GetAllBalances() map[string]int64 {
    b.mu.RLock()
    defer b.mu.RUnlock()

    balances := make(map[string]int64, len(b.accounts))
    for accountID, balance := range b.accounts {
        balances[accountID] = balance
    }

    return balances
}